// mockNATSClientWithCapabilities extends mockNATSClient to support capability endpoint simulation
type mockNATSClientWithCapabilities struct {
	*mockNATSClient

	// Capability responses by endpoint
	capabilityResponses map[string]*component.QueryCapabilities
	capabilityErrors    map[string]error

	// Request tracking
	requestCallCount int32
	requestHistory   []string
	mu               sync.Mutex
}

// newMockNATSClientWithCapabilities creates a mock with capability response support
func newMockNATSClientWithCapabilities() *mockNATSClientWithCapabilities {
	return &mockNATSClientWithCapabilities{
		mockNATSClient:      newMockNATSClient(),
		capabilityResponses: make(map[string]*component.QueryCapabilities),
		capabilityErrors:    make(map[string]error),
		requestHistory:      make([]string, 0),
	}
}

// setCapabilityResponse configures a capability response for a specific endpoint
func (m *mockNATSClientWithCapabilities) setCapabilityResponse(endpoint string, caps *component.QueryCapabilities) {
	m.mu.Lock()
	defer m.mu.Unlock()
	m.capabilityResponses[endpoint] = caps
}

// setCapabilityError configures an error response for a specific endpoint
func (m *mockNATSClientWithCapabilities) setCapabilityError(endpoint string, err error) {
	m.mu.Lock()
	defer m.mu.Unlock()
	m.capabilityErrors[endpoint] = err
}

// Request overrides mockNATSClient.Request to check for capability endpoints first
func (m *mockNATSClientWithCapabilities) Request(ctx context.Context, subject string, data []byte, timeout time.Duration) ([]byte, error) {
	// Track request
	atomic.AddInt32(&m.requestCallCount, 1)
	m.mu.Lock()
	m.requestHistory = append(m.requestHistory, subject)
	m.mu.Unlock()

	// Check if this is a capability endpoint
	m.mu.Lock()
	caps, hasCaps := m.capabilityResponses[subject]
	err, hasErr := m.capabilityErrors[subject]
	m.mu.Unlock()

	if hasErr {
		return nil, err
	}

	if hasCaps {
		return json.Marshal(caps)
	}

	// Fall through to existing requestFunc if set
	if m.mockNATSClient.requestFunc != nil {
		return m.mockNATSClient.requestFunc(ctx, subject, data, timeout)
	}

	return nil, errors.New("no mock response configured")
}

// resetRequestTracking resets the request counter and history
func (m *mockNATSClientWithCapabilities) resetRequestTracking() {
	atomic.StoreInt32(&m.requestCallCount, 0)
	m.mu.Lock()
	m.requestHistory = make([]string, 0)
	m.mu.Unlock()
}

// getRequestCallCount returns the current request count (thread-safe)
func (m *mockNATSClientWithCapabilities) getRequestCallCount() int {
	return int(atomic.LoadInt32(&m.requestCallCount))
}

// getRequestHistory returns a copy of the request history (thread-safe)
func (m *mockNATSClientWithCapabilities) getRequestHistory() []string {
	m.mu.Lock()
	defer m.mu.Unlock()
	history := make([]string, len(m.requestHistory))
	copy(history, m.requestHistory)
	return history
}

