// TestDiscoverForIntent_ConcurrentDiscovery verifies thread-safety of concurrent discovery
func TestDiscoverForIntent_ConcurrentDiscovery(t *testing.T) {
	mockClient := newMockNATSClientWithCapabilities()

	// Configure endpoint with slight delay to simulate real network
	mockClient.requestFunc = func(ctx context.Context, subject string, data []byte, timeout time.Duration) ([]byte, error) {
		// Track request (thread-safe)
		atomic.AddInt32(&mockClient.requestCallCount, 1)
		mockClient.mu.Lock()
		mockClient.requestHistory = append(mockClient.requestHistory, subject)
		mockClient.mu.Unlock()

		// Simulate network delay
		time.Sleep(10 * time.Millisecond)

		if subject == "graph.ingest.capabilities" {
			caps := &component.QueryCapabilities{
				Component: "graph-ingest",
				Version:   "1.0.0",
				Queries: []component.QueryCapability{
					{
						Subject:   "graph.ingest.query.entity",
						Operation: "getEntity",
						Intent: component.QueryIntent{
							Type:     component.IntentTypeEntity,
							Strategy: component.StrategyDirect,
							Scope:    component.ScopeSingle,
						},
					},
				},
			}
			return json.Marshal(caps)
		}

		return nil, nats.ErrTimeout
	}

	// Create router
	router := &IntentRouter{
		natsClient: mockClient,
		routes:     make(map[component.QueryIntent]string),
		fallback: map[component.IntentType]string{
			component.IntentTypeEntity: "graph.ingest.query.entity.fallback",
		},
		logger: slog.Default(),
	}

	intent := component.QueryIntent{
		Type:     component.IntentTypeEntity,
		Strategy: component.StrategyDirect,
		Scope:    component.ScopeSingle,
	}

	// Launch 10 concurrent goroutines calling Route() for same uncached intent
	var wg sync.WaitGroup
	results := make([]string, 10)
	panics := make([]bool, 10)

	for i := 0; i < 10; i++ {
		wg.Add(1)
		go func(index int) {
			defer wg.Done()
			// Use defer-recover to catch any panics
			defer func() {
				if r := recover(); r != nil {
					panics[index] = true
				}
			}()
			results[index] = router.Route(context.Background(), intent)
		}(i)
	}

	wg.Wait()

	// Verify no panics occurred
	for i, didPanic := range panics {
		assert.False(t, didPanic, "goroutine %d should not panic", i)
	}

	// Verify all goroutines got correct result
	for i, subject := range results {
		assert.Equal(t, "graph.ingest.query.entity", subject, "goroutine %d should get correct subject", i)
	}

	// Verify route was discovered and cached
	assert.Equal(t, 1, router.RouteCount(), "route should be cached after concurrent discovery")

	// Verify reasonable request count (not 70 = 7 endpoints × 10 goroutines)
	// Due to concurrent access, multiple goroutines might trigger discovery,
	// but the count should be much less than 70
	callCount := mockClient.getRequestCallCount()
	assert.LessOrEqual(t, callCount, 20, "request count should be reasonable (not 7×10=70)")
	assert.GreaterOrEqual(t, callCount, 1, "at least one discovery should occur")
}

// TestDiscoverForIntent_ConcurrentDifferentIntents verifies concurrent discovery of different intents
func TestDiscoverForIntent_ConcurrentDifferentIntents(t *testing.T) {
	mockClient := newMockNATSClientWithCapabilities()

	// Configure multiple endpoints
	ingestCaps := &component.QueryCapabilities{
		Component: "graph-ingest",
		Version:   "1.0.0",
		Queries: []component.QueryCapability{
			{
				Subject:   "graph.ingest.query.entity",
				Operation: "getEntity",
				Intent: component.QueryIntent{
					Type:     component.IntentTypeEntity,
					Strategy: component.StrategyDirect,
					Scope:    component.ScopeSingle,
				},
			},
		},
	}
	mockClient.setCapabilityResponse("graph.ingest.capabilities", ingestCaps)

	indexCaps := &component.QueryCapabilities{
		Component: "graph-index",
		Version:   "1.0.0",
		Queries: []component.QueryCapability{
			{
				Subject:   "graph.index.query.outgoing",
				Operation: "getOutgoing",
				Intent: component.QueryIntent{
					Type:     component.IntentTypeRelationship,
					Strategy: component.StrategyDirect,
					Scope:    component.ScopeSet,
				},
			},
		},
	}
	mockClient.setCapabilityResponse("graph.index.capabilities", indexCaps)

	// Create router
	router := &IntentRouter{
		natsClient: mockClient,
		routes:     make(map[component.QueryIntent]string),
		fallback: map[component.IntentType]string{
			component.IntentTypeEntity:       "fallback.entity",
			component.IntentTypeRelationship: "fallback.relationship",
		},
		logger: slog.Default(),
	}

	intents := []component.QueryIntent{
		{Type: component.IntentTypeEntity, Strategy: component.StrategyDirect, Scope: component.ScopeSingle},
		{Type: component.IntentTypeRelationship, Strategy: component.StrategyDirect, Scope: component.ScopeSet},
	}

	expectedSubjects := []string{
		"graph.ingest.query.entity",
		"graph.index.query.outgoing",
	}

	// Launch concurrent goroutines for different intents
	var wg sync.WaitGroup
	results := make([]string, len(intents))

	for i, intent := range intents {
		wg.Add(1)
		go func(index int, intentToQuery component.QueryIntent) {
			defer wg.Done()
			results[index] = router.Route(context.Background(), intentToQuery)
		}(i, intent)
	}

	wg.Wait()

	// Verify all intents resolved correctly
	for i, subject := range results {
		assert.Equal(t, expectedSubjects[i], subject, "intent %d should resolve correctly", i)
	}

	// Verify both routes were cached
	assert.Equal(t, 2, router.RouteCount(), "both routes should be cached")
}

